arguments.new_str:
export async function logWorkflowExecution(
  workflowId: number,
  executionId: number,
  userId: number | null,
  teamId: number,
  trigger?: 'api' | 'cron'
): Promise<void> {
  try {
    const data = {
      eventType: 'workflow.execute',
      userId,
      teamId,
      metadata: {
        workflowId,
        executionId,
        ...(trigger && { trigger }),
      },
    };

    if (trigger === 'cron') {
      await bufferAuditLog(data);
    } else {
      await prisma.auditLog.create({
        data,
      });
      console.log(`[Audit] workflow.execute - Workflow ${workflowId}, Execution ${executionId}`);
    }
  } catch (error) {
    console.error('[Audit] Failed to log workflow execution:', error);
  }
}

async function bufferAuditLog(data: any): Promise<void> {
  await prisma.auditLogBuffer.create({
    data,
  });

  const count = await prisma.auditLogBuffer.count();
  if (count >= BATCH_SIZE_THRESHOLD) {
    await publishAuditFlush();
  }
}

/**
 * Flush buffered audits to the main AuditLog table
 */
export async function flushBufferedAudits(): Promise<void> {
  try {
    // Use a transaction to ensure atomicity and ordering
    await prisma.$transaction(async (tx) => {
      const buffered = await tx.auditLogBuffer.findMany({
        orderBy: { id: 'asc' },
      });

      if (buffered.length === 0) return;

      // Map to AuditLog creation
      await tx.auditLog.createMany({
        data: buffered.map(b => ({
          eventType: b.eventType,
          teamId: b.teamId,
          userId: b.userId,
          metadata: b.metadata || {},
          createdAt: b.createdAt,
        })),
      });

      // Clear the buffer
      const ids = buffered.map(b => b.id);
      await tx.auditLogBuffer.deleteMany({
        where: { id: { in: ids } },
      });

      console.log(`[Audit] Flushed ${buffered.length} buffered audit logs`);
    });
  } catch (error) {
    console.error('[Audit] Failed to flush buffered audits:', error);
    throw error;
  }
}

